previewCss:
.darma-loader-darma-custom-315 {
  color: var(--loader-color, #0284c7);
  height: 54px;
  aspect-ratio: 1;
  border: 3px solid var(--loader-secondary-color, #7dd3fc);
  position: relative;
}
.darma-loader-darma-custom-315:before,
.darma-loader-darma-custom-315:after {
  content: "";
  position: absolute;
  width: 20%;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #0284c7);
  animation: 
    darma-loader-darma-custom-315-l8-0 .57s infinite alternate linear -.13s,
    darma-loader-darma-custom-315-l8-1 .35s infinite alternate linear -.23s;
}
.darma-loader-darma-custom-315:after {
  background: var(--loader-secondary-color, #7dd3fc);
  animation: 
    darma-loader-darma-custom-315-l8-0 .29s infinite alternate linear -.11s,
    darma-loader-darma-custom-315-l8-1 .51s infinite alternate linear -.34s;
}
@keyframes darma-loader-darma-custom-315-l8-0 {
  0%,5%  {bottom: 0%}
  95%,to {bottom: 80%}
}
@keyframes darma-loader-darma-custom-315-l8-1 {
  0%,5%  {left: 0%}
  95%,to {left: 80%}
}

